import React, { useState } from 'react';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import styles from './ProductCard.module.css';

export default function ProductCard({ product, featured = false }) {
  const { addItem } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [adding, setAdding] = useState(false);
  const [added, setAdded] = useState(false);

  const handleAddToCart = async (e) => {
    e.stopPropagation();
    if (!user) {
      navigate('/login');
      return;
    }
    setAdding(true);
    addItem(product);
    // Небольшая задержка для анимации
    setTimeout(() => {
      setAdding(false);
      setAdded(true);
      setTimeout(() => setAdded(false), 2000);
    }, 400);
  };

  const placeholderImg = `https://picsum.photos/seed/${product.name}/400/300`;

  return (
    <div className={`${styles.card} ${featured ? styles.featured : ''}`}>
      {/* Бейджи */}
      <div className={styles.badges}>
        {product.is_new     && <span className="badge badge-new">Новинка</span>}
        {product.is_popular && <span className="badge badge-popular">Хит</span>}
        {product.is_day_item && <span className="badge badge-day">Товар дня</span>}
      </div>

      {/* Изображение */}
      <div className={styles.imageWrap}>
        <img
          src={product.image_url || placeholderImg}
          alt={product.name}
          className={styles.image}
          loading="lazy"
          onError={(e) => { e.target.src = placeholderImg; }}
        />
      </div>

      {/* Контент */}
      <div className={styles.body}>
        <p className={styles.category}>
          {categoryLabel(product.category)}
        </p>
        <h3 className={styles.name}>{product.name}</h3>
        {product.description && (
          <p className={styles.desc}>{product.description}</p>
        )}
        <div className={styles.footer}>
          <span className={styles.price}>
            {product.price.toLocaleString('ru-RU')} ₽
          </span>
          <button
            className={`${styles.addBtn} ${added ? styles.added : ''}`}
            onClick={handleAddToCart}
            disabled={adding}
          >
            {added ? '✓ Добавлено' : adding ? '...' : 'В корзину'}
          </button>
        </div>
      </div>
    </div>
  );
}

function categoryLabel(cat) {
  const map = {
    vegetables: '🥕 Овощи',
    fruits:     '🍎 Фрукты',
    desserts:   '🍰 Десерты',
  };
  return map[cat] || cat;
}
